INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$eBPF-based zero-instrumentation sensor$q$, $q$An adaptive eBPF sensor deployed as a Kubernetes DaemonSet automatically captures metrics, logs, traces, and protocol-level data straight from the Linux kernel, with no SDKs, agents inside application code, or redeploys required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$Bring Your Own Cloud (BYOC) architecture$q$, $q$The data plane and telemetry storage run inside the customer's own cloud account or cluster, so raw logs, metrics, and traces never leave the customer's environment.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$Unified logs, metrics and traces$q$, $q$Groundcover correlates infrastructure, application, and Kubernetes event data into a single view so engineers can move from an alert to root cause without switching tools.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$AI observability$q$, $q$Purpose-built monitoring for LLM and AI agent workloads tracks prompts, latency, token usage, and failures alongside traditional application and infrastructure telemetry.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$Root cause analysis workflows$q$, $q$Automated correlation and guided investigation workflows help engineers pinpoint the offending pod, container, or code path behind an incident faster.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$OpenTelemetry support$q$, $q$Native support for OpenTelemetry lets teams combine existing manual instrumentation with the eBPF-collected data in a single pipeline.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$Node-based, predictable pricing$q$, $q$Billing is based on the number of monitored Kubernetes nodes rather than data ingestion volume, so cost does not spike as logging or tracing volume grows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$Enterprise access controls$q$, $q$SSO, role-based access control, and, on the On-Premise tier, isolated authentication and a self-hosted UI support security and compliance requirements.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$Zero-instrumentation eBPF collection removes the engineering burden of manually adding SDKs or agents to every service.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$Node-based pricing is decoupled from data volume, making costs predictable even as logging and tracing grow.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$BYOC architecture keeps raw telemetry inside the customer's own cloud account, which appeals to security-conscious teams.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$Unified view of logs, metrics, traces, and Kubernetes events reduces tool-switching during incident response.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$Dedicated AI observability features address monitoring needs for LLM and agent-based workloads.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$The eBPF-based, Kubernetes-native design means Groundcover is a poor fit for teams running mostly non-containerized infrastructure.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$Node-based pricing can be less predictable for clusters that autoscale heavily, since cost tracks node count rather than a flat subscription.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$The free tier's 12-hour data retention window is short for teams that need to investigate incidents days after they occur.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$As a newer entrant founded in 2021, Groundcover has a smaller ecosystem of integrations and community content than established players like Datadog.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$Enterprise and On-Premise pricing requires per-host negotiation, which can complicate budgeting for large, variable-size fleets.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$What is Groundcover used for?$q$, $q$Groundcover is used by DevOps, platform engineering, and SRE teams to monitor Kubernetes-based applications and infrastructure, collecting logs, metrics, and traces automatically via an eBPF sensor without requiring manual code instrumentation.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$Does Groundcover require code changes to install?$q$, $q$No. Groundcover's eBPF sensor deploys as a Kubernetes DaemonSet and captures telemetry directly from the Linux kernel, so no SDKs, agents, or code-level instrumentation need to be added to application services.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$How does Groundcover pricing work?$q$, $q$Groundcover charges based on the monthly average number of Kubernetes nodes actively monitored by its sensor, rather than the volume of logs, metrics, or traces ingested, with plans ranging from a free tier to Pro, Enterprise, and On-Premise tiers priced per host per month.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$What does BYOC mean for Groundcover customers?$q$, $q$BYOC, or Bring Your Own Cloud, means Groundcover's data plane and telemetry storage run inside the customer's own cloud account or cluster, so raw observability data never has to leave the customer's environment.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$Can Groundcover monitor AI and LLM workloads?$q$, $q$Yes. Groundcover includes AI observability features that track prompts, latency, token usage, and failures for large language model and AI agent workloads alongside standard application and infrastructure telemetry.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$Who are Groundcover's main competitors?$q$, $q$Groundcover competes primarily with Datadog, New Relic, and Grafana Cloud, positioning its eBPF-based zero-instrumentation approach and node-based pricing as an alternative to their agent-based, ingestion-priced observability models.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$Kubernetes production monitoring$q$, $q$Platform and SRE teams deploy Groundcover across production Kubernetes clusters to get automatic visibility into service health, latency, and errors without instrumenting every microservice by hand.$q$, $q$Platform engineering and SRE teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$Monitoring previously dark dev and staging environments$q$, $q$Because Groundcover's pricing is not tied to data volume, teams can afford to monitor development and staging clusters that would be cost-prohibitive to observe under ingestion-based pricing.$q$, $q$Engineering and DevOps teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$AI agent and LLM application observability$q$, $q$Teams building products on top of large language models use Groundcover's AI observability tooling to track prompt performance, latency, and failures in production.$q$, $q$AI and ML engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$Free$q$, $q$$0$q$, $q$Monthly$q$, NULL, $q$["12-hour data retention","Slack community support","No credit card required","BYOC deployment"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$Pro$q$, $q$$30 per host$q$, $q$Monthly$q$, NULL, $q$["All integrations and data sources","SSO support","Standard data retention","Standard support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$Enterprise$q$, $q$$35 per host$q$, $q$Monthly$q$, NULL, $q$["Everything in Pro","RBAC support","Unlimited data retention","Premium support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$On Premise$q$, $q$$50 per host$q$, $q$Monthly$q$, NULL, $q$["Everything in Enterprise","Self-hosted data plane","Self-hosted UI","Isolated authentication"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Groundcover is a cloud-native observability platform that uses eBPF sensor technology to automatically collect metrics, logs, and distributed traces from Kubernetes workloads without requiring any code changes or manual instrumentation.$q$, $q$Founded in 2021 and based in Tel Aviv, Israel, the company has raised roughly 60 million dollars in venture funding, including a 35 million dollar Series B round in April 2025, to expand its eBPF-based approach to observability into the US market.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$At the core of Groundcover is its adaptive eBPF sensor, which runs as a lightweight DaemonSet on every Kubernetes node and hooks into the Linux kernel to capture application and infrastructure telemetry the instant a workload runs, eliminating the need for SDKs or code-level instrumentation.$q$, $q$The platform correlates logs, metrics, traces, and Kubernetes events in a single interface, and includes root cause analysis workflows plus dedicated AI observability tooling for monitoring large language model and AI agent workloads alongside conventional application performance data.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Groundcover breaks from the industry norm of ingestion-based pricing by charging based on the monthly average number of Kubernetes nodes monitored, regardless of the volume of telemetry those nodes generate.$q$, $q$Plans range from a free tier with 12-hour retention up through Pro at 30 dollars per host per month, Enterprise at 35 dollars per host per month, and a fully self-hosted On-Premise tier at 50 dollars per host per month for organizations with strict data-residency requirements.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('66cb9934-6740-4aa9-bd5c-6b81c6f665af', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Integrated email and calendar$q$, $q$Full email client and shared calendaring with scheduling, reminders, and address book integration form the core of the groupware suite.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$File sharing and document editing$q$, $q$Built-in file storage integrates with Collabora Online for real-time, in-browser document editing and collaboration.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$CRM and project management$q$, $q$The Professional tier adds contact and deal tracking, project management, and a Kanban-style board called Studio for building custom workflows.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Support ticketing and helpdesk$q$, $q$A built-in helpdesk module lets teams manage customer or internal support tickets directly inside the same platform used for email and files.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Invoicing and time tracking$q$, $q$Time tracking, quoting, and invoicing modules let small businesses manage billing without a separate finance tool.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Chat and video calling$q$, $q$A Rocket.Chat-based add-on brings team chat and video conferencing into the same suite as email and files.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Self-hosted or cloud deployment$q$, $q$Organizations can self-host the AGPL-licensed Community edition on their own servers or run a fully managed version on Intermesh's cloud infrastructure.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Unlimited users on the free edition$q$, $q$The Community edition supports an unlimited number of users at no license cost, with only the advanced business modules gated behind the paid tier.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$The Community edition is free, open source, and supports unlimited users, making it inexpensive to deploy at scale.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Self-hosting gives organizations full control over data location, which matters for public-sector and privacy-conscious deployments.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Bundles groupware, CRM, invoicing, and helpdesk functionality in a single suite rather than requiring separate tools.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Has been in continuous development since 2003, giving it a long production track record versus newer self-hosted alternatives.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Offers both self-hosted and managed cloud deployment options, so organizations can choose based on their operational capacity.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$The user interface is dated compared to modern SaaS collaboration tools like Google Workspace or Microsoft 365.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Self-hosting requires PHP and database administration skills, which smaller organizations may not have in-house.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Advanced business features are locked behind the paid Professional tier and add-ons rather than included in the free edition.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Support for the free Community edition relies on community forums rather than guaranteed response times.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Smaller ecosystem of third-party integrations and plugins compared to larger groupware and productivity platforms.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Is Group Office free to use?$q$, $q$Yes, the Community edition of Group Office is free and open source under the AGPL license, and it can be self-hosted with an unlimited number of users, though it excludes the paid Professional-tier business modules.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Can Group Office be self-hosted?$q$, $q$Yes, Group Office can be downloaded from GitHub and self-hosted on your own server infrastructure, or you can use Intermesh's managed Online cloud plan if you prefer not to run your own server.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$What is the difference between Group Office Community and Professional editions?$q$, $q$The Community edition includes core groupware features like email, calendar, files, and document editing for free, while the Professional edition adds business tools such as support ticketing, time tracking, project management, invoicing, and helpdesk support for a license fee.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Does Group Office include a CRM?$q$, $q$Yes, Group Office includes CRM-style contact and deal management as part of its Professional edition, alongside its email, calendar, and file-sharing tools.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Who develops Group Office?$q$, $q$Group Office is developed and maintained by Intermesh, a software company headquartered in 's-Hertogenbosch, Netherlands, with the project's first release dating back to 2003.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$What are the main alternatives to Group Office?$q$, $q$Common alternatives include EGroupware, Nextcloud, Zimbra, and hosted suites like Google Workspace and Microsoft 365, though Group Office differentiates itself by bundling CRM, invoicing, and helpdesk tools into the same open source groupware suite.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Self-hosted email and collaboration for public-sector organizations$q$, $q$Government agencies and schools deploy Group Office on their own infrastructure to keep email, calendars, and files under direct organizational control.$q$, $q$Government and education IT teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Small business CRM and invoicing$q$, $q$Small businesses use the Professional edition to manage contacts, projects, time tracking, and invoicing in one suite instead of stitching together separate tools.$q$, $q$Small and mid-sized businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Low-cost productivity suite alternative$q$, $q$Cost-conscious organizations replace hosted productivity suites with Group Office's free, self-hosted Community edition for email, calendar, and file sharing.$q$, $q$Budget-constrained organizations and nonprofits$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Community$q$, $q$Free$q$, $q$One-time (self-hosted)$q$, NULL, $q$["Unlimited users","Email, calendar, files, and document editing","Notes, tasks, and device sync","Free updates and patches on Community features"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Professional$q$, $q$About 439 euros license plus 219 euros per year for updates$q$, $q$One-time license plus annual update fee$q$, NULL, $q$["1 to 100 users","Support ticketing","Time tracking and projects","Kanban board (Studio)","Newsletter tool","Helpdesk support (9 to 5 CET/CEST)"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$Online (Cloud)$q$, $q$From about $12/month$q$, $q$Monthly$q$, NULL, $q$["Fully managed cloud hosting","Core groupware features","Optional paid add-ons for chat, finance, and document search"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Group Office is an open source groupware and CRM platform, first released in 2003 and developed by the Dutch company Intermesh, that bundles email, calendar, file sharing, contact management, and business tools into a single self-hostable suite.$q$, $q$The product is distributed under a dual-license model: a free AGPL-licensed Community edition available on GitHub for self-hosting, and a paid Professional edition plus a fully managed cloud offering from Intermesh.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Group Office's core groupware stack covers email, shared calendars, address books, file storage, document editing through Collabora Online, notes, tasks, and device synchronization for unlimited users on the free Community edition.$q$, $q$The paid Professional tier and add-ons extend this into a fuller business suite, adding CRM-style contact and deal tracking, support ticketing, time tracking, project management with a Kanban-style board, invoicing and quoting, and Rocket.Chat-based chat and video calling.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Community edition is free to self-host with unlimited users but excludes the Professional-tier business modules, making it a strong fit for organizations comfortable managing their own server.$q$, $q$Organizations that want the fuller feature set can license the Professional edition for a one-time fee plus an annual update fee, or use Intermesh's cloud-hosted Online plan starting at roughly 12 dollars per month, with additional storage and modules priced as separate add-ons.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('75c612e3-c807-4326-9997-c8d5eb872687', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$AI blog post generation$q$, $q$Generates full blog post drafts and outlines from a target keyword, cutting the time needed to produce SEO-oriented content.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Keyword research$q$, $q$Provides search volume, keyword difficulty, and related keyword suggestions to guide content topic selection.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Competitor content analysis$q$, $q$Shows which keywords a competitor's domain ranks for along with backlink data, helping users find content gaps to target.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$On-page content optimization scoring$q$, $q$Scores an article against top-ranking competitors while it is being written, suggesting terms and structure to improve its SEO potential.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Rank tracking$q$, $q$Monitors how published articles move in Google search rankings over time so users can measure the impact of their content.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Chrome extension$q$, $q$Surfaces keyword volume and competitor ranking data directly inside Google search results for quick research without leaving the browser.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Blog-to-audio and blog-to-video conversion$q$, $q$Converts written blog posts into audio or video formats to extend content into additional distribution channels.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Multi-user collaboration$q$, $q$Pro and Agency plans support multiple user accounts and writer draft sharing for small content teams.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Bundles keyword research, AI writing, on-page optimization, and rank tracking into a single subscription instead of separate tools.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Simple, blogger-focused workflow makes it approachable for solo creators and small teams without dedicated SEO staff.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Chrome extension provides fast, in-context keyword and competitor data while browsing Google search results.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Annual billing offers a substantial discount, roughly 40 percent, versus paying month to month.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Strong reported third-party review scores on platforms like G2 and Capterra.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Monthly article and keyword-tracking limits on each tier mean high-volume publishers may need to jump to a more expensive plan quickly.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$AI-generated drafts still typically require human editing to match brand voice and factual accuracy, common to AI writing tools generally.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Fewer advanced SEO features, like full site audits or extensive backlink databases, compared to dedicated enterprise SEO suites such as Ahrefs or SEMrush.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Ongoing acquisition and integration into SEOptimer creates some uncertainty about the product's long-term standalone roadmap.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Only a 7-day free trial, which is shorter than some competing AI SEO tools.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$What does GrowthBar do?$q$, $q$GrowthBar is an AI-powered SEO tool that generates blog post drafts, researches keywords, analyzes competitor content, and tracks search rankings to help marketers and bloggers publish content that ranks on Google.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$How much does GrowthBar cost?$q$, $q$GrowthBar's Standard plan starts at $36 per month billed monthly (about $20.30 per month billed annually), with Pro at $74.25 per month and Agency at $149.25 per month, each raising limits on AI articles, tracked keywords, and user accounts.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Does GrowthBar offer a free trial?$q$, $q$Yes, GrowthBar offers a 7-day free trial on all plans, along with a money-back guarantee if a refund is requested shortly after the trial period ends.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Who founded GrowthBar?$q$, $q$GrowthBar was founded in 2020 by Hailey Friedman and Mark Spera, the co-founders of the Growth Marketing Pro blog, and the company has since been acquired by SEO platform SEOptimer.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Does GrowthBar include a Chrome extension?$q$, $q$Yes, GrowthBar includes a Chrome extension that surfaces keyword volume, difficulty, and competitor ranking data directly inside Google search results, and unlimited use of the extension is included on every plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$What are the main alternatives to GrowthBar?$q$, $q$Common alternatives include Surfer SEO, Frase, Jasper, Content at Scale, and more traditional SEO suites like Ahrefs and SEMrush, depending on whether a team prioritizes AI writing or deeper technical SEO analysis.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$SEO content production for solo bloggers$q$, $q$Individual bloggers use GrowthBar to research keywords, draft optimized posts, and track rankings without hiring a dedicated SEO specialist.$q$, $q$Solo bloggers and content creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Content marketing for small teams$q$, $q$Small marketing teams use GrowthBar's multi-user plans to collaborate on keyword research and draft sharing while scaling content output.$q$, $q$Small marketing and content teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Competitor content gap analysis$q$, $q$Marketers use GrowthBar's competitor analysis tools to identify keywords a rival domain ranks for and build content to target those gaps.$q$, $q$SEO and content marketers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Standard$q$, $q$$36/month (or $20.30/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["25 AI blog articles or audits","500 AI paragraph generations","2 blog-to-audio/video conversions","Unlimited meta descriptions and blog ideas","Unlimited keyword research","Track 25 keywords across 1 site","2 user accounts"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Pro$q$, $q$$74.25/month (or $55.30/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["100 AI blog articles or audits","2,000 AI paragraph generations","10 blog-to-audio/video conversions","Track 1,000 keywords across 3 sites","5 user accounts","Writer draft sharing"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$Agency$q$, $q$$149.25/month (or $90.30/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["300 AI blog articles or audits","5,000 AI paragraph generations","25 blog-to-audio/video conversions","Track 5,000 keywords across 25 sites","10 user accounts","Writer draft sharing"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GrowthBar is an AI-powered SEO and content writing tool, founded in 2020 by Hailey Friedman and Mark Spera of Growth Marketing Pro, that combines keyword research, AI blog writing, and rank tracking in a single subscription product.$q$, $q$The company has been acquired by SEO audit platform SEOptimer and is being integrated into its broader product suite, though GrowthBar continues to operate as an actively sold, standalone plan.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$GrowthBar's AI writing engine generates full blog post drafts, outlines, meta descriptions, and other marketing copy from a target keyword, alongside an on-page content optimization score as the article is written.$q$, $q$A companion Chrome extension surfaces keyword volume, difficulty, and competitor ranking data directly inside Google search results, complementing the platform's built-in keyword research, competitor content analysis, and rank tracking tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$GrowthBar offers three monthly subscription tiers, Standard, Pro, and Agency, scoped mainly by the number of AI-generated articles, tracked keywords, and user accounts included, with annual billing cutting the effective monthly price by roughly 40 percent.$q$, $q$All plans include a 7-day free trial, unlimited Chrome extension use, and the ability to cancel at any time, with Standard starting at $36 per month and Agency topping out at $149.25 per month on monthly billing.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e7ffaae8-d151-4f81-9afa-a3539c05ff4f', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Warehouse-native architecture$q$, $q$Connects directly to a company's existing data warehouse instead of requiring a separate proprietary event pipeline, keeping experiment and analytics data in one place.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Feature flag management$q$, $q$Lets engineering teams roll out features gradually, target specific segments, and instantly disable problematic releases without redeploying code.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$A/B testing and experimentation$q$, $q$Runs Bayesian and frequentist statistical analysis on experiment results computed directly against warehouse data, including multi-armed bandit testing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Product analytics$q$, $q$Provides funnel, retention, and metric-tracking dashboards built on the same underlying data model used for experiments and feature flags.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Open source, MIT-licensed core$q$, $q$The bulk of GrowthBook's codebase is open source under the MIT license and available on GitHub, with a large and active self-hosting community.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Visual editor$q$, $q$Available on Pro and Enterprise tiers, the visual editor lets non-engineers set up and modify experiments without writing code.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Enterprise access controls$q$, $q$SSO, SCIM provisioning, advanced permissioning, and exportable audit logs support security and compliance needs on the Enterprise tier.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Flexible deployment$q$, $q$Available as a fully managed cloud service or a self-hosted deployment, with feature parity on the core flagging and experimentation functionality.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Genuinely open source MIT-licensed core with a free, fully functional self-hosting option, not just a limited trial.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Warehouse-native design avoids duplicating event data into a separate proprietary analytics store, reducing vendor lock-in.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Combines feature flags, experimentation, and product analytics in one tool instead of three separate point solutions.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Free tiers exist on both the cloud and self-hosted paths, lowering the barrier to trying the full statistics engine.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Backed by a large and active GitHub community with thousands of stars and thousands of reported companies using the platform.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$The warehouse-native model requires a company to already have a modern data warehouse set up, which can be a barrier for smaller teams without one.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Self-hosting requires engineering resources to deploy, maintain, and upgrade the platform over time.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Advanced features like SSO, SCIM, and audit logs are gated behind Enterprise pricing that requires a custom quote rather than being self-serve.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Pro plan is priced per seat, which can get expensive quickly for larger product and engineering organizations.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$As a warehouse-dependent tool, real-time experiment results can be slower than platforms that use a dedicated, purpose-built event pipeline.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Is GrowthBook free to use?$q$, $q$Yes, GrowthBook offers a free, fully functional Open Source edition for self-hosting and a free Starter plan on GrowthBook Cloud for up to 3 users, both including unlimited feature flags and experiments.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$What does it mean that GrowthBook is warehouse-native?$q$, $q$It means GrowthBook connects directly to a company's existing data warehouse, such as Snowflake, BigQuery, or Redshift, to run its statistical analysis, rather than requiring event data to be duplicated into a separate proprietary analytics store.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Who founded GrowthBook and when?$q$, $q$GrowthBook was founded in 2020 by Jeremy Dorn and Graham McNicoll, went through Y Combinator's Winter 2022 batch, and is headquartered in San Francisco.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$How much does GrowthBook Pro cost?$q$, $q$The GrowthBook Cloud Pro plan costs $40 per seat per month for up to 50 users and adds a visual editor, multi-armed bandits, safe rollouts, and premium support on top of the free Starter plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Can GrowthBook be self-hosted?$q$, $q$Yes, GrowthBook can be self-hosted for free using its open source edition, or organizations can license a self-hosted Enterprise tier for advanced access control, SSO, SCIM, and dedicated support.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$What are GrowthBook's main competitors?$q$, $q$GrowthBook competes with commercial feature flagging and experimentation platforms like LaunchDarkly, Optimizely, Statsig, and Split, as well as open source feature-flag-focused tools like Unleash and Flagsmith.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Gradual feature rollouts$q$, $q$Engineering teams use GrowthBook's feature flags to release new functionality to a subset of users, monitor for issues, and roll back instantly without a redeploy.$q$, $q$Engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Warehouse-native A/B testing$q$, $q$Product and data teams run A/B tests and multi-armed bandit experiments directly against their existing data warehouse without duplicating event data into a separate system.$q$, $q$Product and data science teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Self-hosted experimentation for cost control$q$, $q$Startups and engineering-led companies self-host GrowthBook's open source edition to run unlimited feature flags and experiments without paying per-seat SaaS fees.$q$, $q$Startups and engineering-led organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Starter (Cloud)$q$, $q$Free$q$, $q$Monthly$q$, NULL, $q$["Up to 3 users","Unlimited feature flags and experiments","Bring your own warehouse or managed warehouse","Unlimited traffic","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Pro (Cloud)$q$, $q$$40/seat/month$q$, $q$Monthly$q$, NULL, $q$["Up to 50 users","Visual editor","Multi-armed bandits","Safe rollouts","Customizable dashboards","Advanced permissioning","Power calculator","Premium support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Enterprise (Cloud)$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["All Pro features","Ramp schedules","Approval workflows","SSO and SCIM provisioning","Exportable audit logs","99.99% uptime SLA","Dedicated support and training"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Open Source (Self-Hosted)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited feature flags and experiments","Bring your own warehouse","Community support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$Enterprise (Self-Hosted)$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["All open source features","Advanced access control","SSO and SCIM provisioning","Visual editor","Multi-armed bandits","Sticky bucketing and holdouts","Dedicated support and training"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GrowthBook is an open source platform, founded in 2020 by Jeremy Dorn and Graham McNicoll, that unifies feature flagging, A/B testing and experimentation, and product analytics into a single tool teams can self-host for free or run on GrowthBook Cloud.$q$, $q$The company went through Y Combinator's Winter 2022 batch, is based in San Francisco with roughly 40 employees, and raised a Series A round in June 2025 that brought its total funding to about $23.1 million.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$GrowthBook's defining architectural feature is being warehouse-native: rather than duplicating event data into a proprietary store, it connects directly to a company's existing data warehouse, such as Snowflake, BigQuery, or Redshift, and runs its statistics engine against that data.$q$, $q$The platform combines feature flag management, A/B testing with Bayesian and frequentist statistics, multi-armed bandits, and product analytics like funnels and retention in one interface, with the bulk of the codebase released under the permissive MIT license.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$GrowthBook offers free tiers on both its cloud and self-hosted paths: a 3-user Starter cloud plan and a fully self-hostable open source edition, each including unlimited feature flags and experiments.$q$, $q$Paid tiers add collaboration and enterprise controls, with Pro at $40 per seat per month adding a visual editor and premium support, and custom-priced Enterprise tiers, cloud or self-hosted, adding SSO, SCIM, audit logs, and dedicated support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('97fb4c3c-be2d-434f-9e6a-cd5f7f600da0', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Warehouse-native audience building$q$, $q$Marketers build customer segments directly against the company's own cloud data warehouse instead of a separate, vendor-hosted copy of customer data.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Unlimited destinations$q$, $q$Activated audiences can be pushed to an unlimited set of advertising, email, SMS, and other marketing destinations.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$AI Studio and growth agents$q$, $q$Agentic AI tooling automates parts of audience building, journey design, and campaign optimization.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Journey personalization and experimentation$q$, $q$Supports multi-step, omnichannel customer journey orchestration along with built-in experimentation capabilities.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Incrementality and uplift measurement$q$, $q$Measures the true causal impact of campaigns rather than relying solely on last-touch attribution.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Query-in-place governance$q$, $q$Reads and writes data in place within the customer's warehouse rather than duplicating sensitive customer records into GrowthLoop's own infrastructure.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Enterprise security and compliance$q$, $q$SOC 2 Type II compliance, PII management, data governance controls, an application firewall, and SSO support address enterprise security requirements.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Role-based access control$q$, $q$Unlimited users can be added with role- and feature-based permissions to control who can build and activate audiences.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Warehouse-native, query-in-place architecture avoids duplicating sensitive customer data into a separate vendor-hosted system.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Unlimited audiences, templates, and destinations are included at every pricing tier rather than gated by usage caps.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$AI Studio's agentic recommendations can automate parts of campaign building and audience optimization.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Built-in incrementality measurement gives marketing teams a more rigorous view of campaign impact than last-touch attribution alone.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Enterprise-grade governance features, including SOC 2 Type II, PII management, and an application firewall, suit large, security-conscious organizations.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Fully custom, quote-based pricing means there is no published starting price, making it harder to quickly compare costs against competitors.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Requires an existing, well-organized cloud data warehouse, making it a poor fit for companies without that data infrastructure already in place.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Best suited to mid-market and enterprise teams, with less obvious fit for small businesses or solo marketers.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$As a smaller, less universally known platform compared to Segment or Braze, it may have a smaller pool of external integration partners and community resources.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Reports of offices in multiple cities suggest a distributed, multi-office organization that may complicate evaluating a single point of contact.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$What is GrowthLoop?$q$, $q$GrowthLoop is a composable customer data platform that lets marketing teams build audiences, orchestrate customer journeys, and run AI-driven campaigns directly on top of their existing cloud data warehouse instead of a separate, vendor-hosted data store.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$How much does GrowthLoop cost?$q$, $q$GrowthLoop does not publish list pricing; plans are tiered by the number of customer records under management, Basic up to 1 million, Growth up to 10 million, Enterprise for 10 million-plus, and require contacting sales for a custom quote.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$When was GrowthLoop founded?$q$, $q$GrowthLoop was founded in 2015 as Flywheel Software by David Joosten and Chris Sell, later rebranding as GrowthLoop as its product evolved into the composable CDP category.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$What does composable CDP mean?$q$, $q$A composable CDP like GrowthLoop reads and writes customer data directly within a company's own cloud data warehouse rather than requiring that data to be copied into a separate, vendor-owned data store.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Does GrowthLoop use AI?$q$, $q$Yes, GrowthLoop's AI Studio includes growth agents and agentic recommendations designed to automate parts of audience building, journey orchestration, and campaign optimization.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Who are GrowthLoop's main competitors?$q$, $q$GrowthLoop competes with other composable CDP and reverse ETL vendors like Hightouch and Census, as well as traditional customer data platforms such as Segment, Braze, and Adobe's customer data offerings.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Warehouse-native audience activation$q$, $q$Marketing teams at data-mature companies build and activate customer segments directly from their Snowflake or BigQuery warehouse without duplicating data into a separate CDP.$q$, $q$Enterprise and mid-market marketing teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$AI-assisted campaign optimization$q$, $q$Growth marketers use GrowthLoop's AI Studio to automate audience recommendations and campaign optimization across advertising and lifecycle channels.$q$, $q$Growth and lifecycle marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Incrementality measurement for marketing spend$q$, $q$Analytics and marketing teams use GrowthLoop's uplift measurement tools to quantify the true causal impact of campaigns rather than relying on last-touch attribution.$q$, $q$Marketing analytics teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Basic$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Up to 1 million customer records","Self-serve audience building","Unlimited destinations","Email and Slack support","Standard onboarding"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Growth$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Up to 10 million customer records","AI Studio and growth agents","Journey personalization and experimentation","Email and Slack support","Standard onboarding"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["10 million-plus customer records","Dedicated solutions architect","Data engineering support","Hands-on launch services","Advanced governance and SSO"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GrowthLoop is a composable customer data platform that lets marketing teams build audiences and orchestrate customer journeys directly on top of an existing cloud data warehouse like Snowflake, BigQuery, or Databricks, rather than copying data into a separate vendor-owned store.$q$, $q$The company was founded in 2015 as Flywheel Software by David Joosten and Chris Sell, later rebranding as GrowthLoop, and has raised roughly $93.8 million in funding, including a growth equity investment from The Jordan Company in 2022 and a Series D round in October 2025.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$GrowthLoop's self-serve audience builder lets marketers create unlimited active and saved audience segments directly against warehouse tables, then push those audiences to an unlimited number of downstream advertising, email, and SMS destinations.$q$, $q$An AI Studio layer adds growth agents and agentic recommendations for automating campaign building and optimization, alongside journey personalization, experimentation tooling, and incrementality and uplift measurement to quantify real campaign impact.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$GrowthLoop uses fully custom, quote-based pricing tiered primarily by the number of customer records under management: Basic for up to 1 million records, Growth for up to 10 million, and Enterprise for 10 million or more.$q$, $q$Core platform capabilities are available across all tiers, with Enterprise adding a dedicated solutions architect, data engineering support, and hands-on launch services beyond the standard email and Slack support included on Basic and Growth.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('45050474-ebf1-4a46-89d7-f47f4521c45f', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Hosted creator storefront$q$, $q$Every seller gets a Gumroad profile page and individual product pages that can be linked directly or embedded on an external site.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$One-time and recurring sales$q$, $q$Supports one-time digital product purchases as well as recurring memberships and subscriptions for ongoing content or software access.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Merchant of Record tax handling$q$, $q$Gumroad calculates, collects, and remits sales tax and VAT on behalf of creators across the jurisdictions where their customers are located.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Discover marketplace$q$, $q$An in-platform marketplace lets new customers find a creator's products organically, in exchange for a higher transaction fee on those sales.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$No monthly subscription fee$q$, $q$Creators pay nothing to list products and only owe Gumroad a percentage when they actually make a sale.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Email audience tools$q$, $q$Creators can send email updates directly to past customers to promote new products or content.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Global payouts$q$, $q$Supports payouts via direct deposit or PayPal depending on the creator's country.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Broad digital product support$q$, $q$Supports e-books, courses, software, templates, music, and other digital content, plus podcast and SaaS-style subscriptions.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$No monthly subscription fee means creators can start selling with essentially no upfront cost.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Merchant of Record status removes the burden of calculating and remitting international sales tax and VAT.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Supports both one-time digital products and recurring memberships or subscriptions in the same platform.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Long operating history since 2011 and strong brand recognition within the indie creator and bootstrapper community.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Optional Discover marketplace gives creators a built-in channel for organic customer discovery.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Transaction fees, especially the 30% Discover marketplace rate, are higher than the percentage-based fees of some competitors.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Does not support physical goods, so creators selling both physical and digital products need a separate platform for the physical side.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Because there is no monthly fee, Gumroad's total cost can exceed a flat-fee competitor once a creator reaches meaningful sales volume.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Restricted category list, such as no adult content, sports betting products, or securities, limits which types of digital businesses can use the platform.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Smaller feature set for advanced marketing automation or affiliate management compared to larger e-commerce platforms.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$How does Gumroad pricing work?$q$, $q$Gumroad has no monthly subscription fee; it charges 10% plus $0.50 per transaction on sales made through a creator's own profile or direct links, and 30% on sales that come through Gumroad's own Discover marketplace.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Who founded Gumroad and when?$q$, $q$Gumroad was founded in 2011 by designer Sahil Lavingia, who built the first version of the product over a single weekend before it attracted roughly 50,000 visitors with no marketing spend.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Does Gumroad handle sales tax for creators?$q$, $q$Yes, as of January 1, 2025, Gumroad became a Merchant of Record, meaning it calculates, collects, and remits sales tax and VAT on behalf of creators across the jurisdictions where their customers are located.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Can I sell subscriptions on Gumroad?$q$, $q$Yes, Gumroad supports recurring memberships and subscriptions, including use cases like podcast memberships, ongoing course access, and SaaS-style subscription products.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Is Gumroad venture-backed?$q$, $q$Gumroad raised early venture funding, including a Series A led by Kleiner Perkins, but after a failed 2015 Series B attempt it moved away from large VC rounds and instead raised $5 million through equity crowdfunding in 2021, letting creators and customers become shareholders.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$What can't I sell on Gumroad?$q$, $q$Gumroad prohibits physical goods, securities, sports betting products, copyright-infringing content, and adult content, focusing the platform on legitimate digital products and services.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Selling digital products without a storefront build$q$, $q$Independent creators use Gumroad to sell e-books, templates, and courses through a ready-made storefront without building custom e-commerce infrastructure.$q$, $q$Independent creators and authors$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$International sales without tax compliance overhead$q$, $q$Global creators rely on Gumroad's Merchant of Record status to handle sales tax and VAT collection automatically as they sell to customers in different countries.$q$, $q$Creators selling to an international audience$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Membership and subscription content$q$, $q$Podcasters, course creators, and solo software builders use Gumroad's recurring billing to run memberships and subscription products.$q$, $q$Podcasters, course creators, and indie software makers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Direct Sales$q$, $q$10% + $0.50 per transaction$q$, $q$Per transaction (no monthly fee)$q$, NULL, $q$["Sales through creator's own profile or direct links","No monthly subscription cost","Merchant of Record tax handling","Support for one-time and recurring products"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$Discover Marketplace Sales$q$, $q$30% per transaction$q$, $q$Per transaction (no monthly fee)$q$, NULL, $q$["Sales from new customers found via Gumroad's Discover marketplace","Built-in organic customer acquisition","Merchant of Record tax handling"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Gumroad is a creator commerce platform, founded in 2011 by designer Sahil Lavingia, that lets independent creators sell digital products, courses, and memberships directly to their audience without a monthly subscription fee.$q$, $q$After a failed Series B attempt in 2015 forced major layoffs, Gumroad shifted away from traditional venture funding, later raising $5 million through an equity crowdfunding campaign in 2021 that let creators and customers become shareholders.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Creators can sell one-time digital products as well as recurring memberships and subscriptions through a hosted Gumroad profile page or an embeddable checkout linked from their own site or social media.$q$, $q$As of January 2025, Gumroad operates as a Merchant of Record, taking on responsibility for calculating, collecting, and remitting sales tax and VAT on behalf of sellers across the jurisdictions where their customers are located.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Gumroad charges no monthly subscription fee; creators only pay when a sale happens, with a 10% plus $0.50 fee on sales made through their own profile or direct links.$q$, $q$Sales that originate from Gumroad's own Discover marketplace, where new customers find a product organically rather than through a link the creator shared, carry a higher 30% fee reflecting the added customer acquisition Gumroad provides.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('3755468e-f104-4abb-9bde-b2e658eb3053', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Verified Knowledge Cards$q$, $q$Company knowledge is organized into short Cards that carry explicit verification status and expiration dates, so outdated information is flagged for review rather than silently persisting.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$AI Knowledge Agents$q$, $q$AI agents deliver cited, permission-aware answers to employee questions, sourced directly from an organization's verified Cards.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Slack integration$q$, $q$Knowledge Agents attached to Slack channels automatically suggest verified answers to employee questions without a slash command, and let teammates search, share, and capture Cards without leaving Slack.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Browser extension$q$, $q$A browser extension surfaces relevant Cards and answers directly inside the tools employees are already using, such as their CRM or support desk.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$MCP support$q$, $q$Support for the Model Context Protocol lets Guru's governed knowledge base be surfaced inside other AI agents and assistants an organization relies on.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Enterprise integrations$q$, $q$Native integrations with Salesforce, Zendesk, and Jira bring Guru's knowledge layer into customer support and sales workflows.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Permission-aware access control$q$, $q$Role-based access control and SSO/SCIM provisioning ensure AI answers respect the same permissions as the underlying source content.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Compliance certifications$q$, $q$SOC 2 Type II, HIPAA, and GxP compliance support deployment in regulated industries with strict data-handling requirements.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Verified Cards with expiration dates directly address the stale-knowledge problem common in traditional wikis.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Deep, purpose-built Slack integration, reflecting Slack's own early investment in the company, makes Guru easy to adopt inside existing chat workflows.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Permission-aware AI answers with citations reduce the risk of AI-generated responses surfacing unauthorized or unverified information.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Strong compliance posture, including SOC 2 Type II, HIPAA, and GxP, suits regulated industries like healthcare and financial services.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Guru for Good offers discounted pricing for eligible nonprofit organizations.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$No permanent free tier; only a 30-day free trial is available before a paid plan is required.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$A 10-seat minimum on paid plans raises the effective entry cost above the advertised per-seat price for very small teams.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Builder and Enterprise/Expert pricing is not published, requiring a sales conversation to get an actual quote.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Less general-purpose than broad workplace search tools, since Guru's value depends on teams maintaining well-curated Cards.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Feature set is narrower than an all-in-one wiki and documentation tool like Notion or Confluence for teams that also need long-form docs and project management.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$What is Guru used for?$q$, $q$Guru is used to organize company knowledge into short, verified Cards and deliver AI-powered, cited answers to employee questions inside Slack, browsers, and other everyday work tools.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Does Guru have a free plan?$q$, $q$No, Guru does not offer a permanent free tier, but it provides a 30-day free trial across its plans so teams can evaluate core features before committing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$How much does Guru cost?$q$, $q$Guru's Starter plan is publicly listed at $25 per seat per month on annual billing with a 10-seat minimum, putting the effective floor at $250 per month, while Builder and Enterprise pricing require contacting Guru's sales team for a custom quote.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$How does Guru integrate with Slack?$q$, $q$Guru's Knowledge Agents can be connected to specific Slack channels to automatically suggest verified answers to employee questions, and teammates can search, share, and capture Cards without leaving Slack.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Who founded Guru and when?$q$, $q$Guru was founded in 2013 by Rick Nucci and Mitchell Stewart and publicly launched in early 2014; the company is headquartered in Philadelphia, Pennsylvania.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$What makes Guru's knowledge base different from a regular wiki?$q$, $q$Guru's Cards carry explicit verification status and expiration dates, so subject-matter experts are prompted to review and re-verify content, which helps prevent the stale, outdated information common in traditional wikis.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Customer support knowledge base$q$, $q$Support teams use Guru's verified Cards and AI Knowledge Agents to answer customer questions accurately and quickly without digging through outdated documentation.$q$, $q$Customer support teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Sales enablement$q$, $q$Sales teams use Guru to surface verified product and pricing information directly inside their CRM and Slack workflows during deal cycles.$q$, $q$Sales and revenue teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Internal HR and IT knowledge management$q$, $q$HR and IT teams use Guru to maintain verified, expiring policy and process documentation that employees can trust is current.$q$, $q$HR and IT operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Starter$q$, $q$$25/seat/month billed annually ($30/seat/month billed monthly)$q$, $q$Monthly or annual, 10-seat minimum$q$, NULL, $q$["AI-powered search","Verified Knowledge Cards","Browser extension","Slack integration","30-day free trial"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Builder$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Everything in Starter","AI Suggest","Custom collections","Advanced permissions","Integrations with Salesforce, Zendesk, and Jira"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$Enterprise (Expert)$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Everything in Builder","Advanced AI capabilities","Premium analytics","Dedicated support","Custom integrations","SSO and SCIM provisioning"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Guru is an AI-powered knowledge management platform, founded in 2013 by Rick Nucci and Mitchell Stewart and based in Philadelphia, that organizes company knowledge into verified Cards with built-in expiration dates so information doesn't silently go stale.$q$, $q$The company has raised roughly $68 to $71 million in funding across multiple rounds, including a $25 million Series B led by Thrive Capital in 2018 and a later round led by Accel with participation from Slack's own venture fund.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Guru's Knowledge Agents deliver AI-powered, cited answers to employee questions directly inside Slack, browsers, and other everyday tools, automatically suggesting verified Cards in a connected Slack channel without requiring a slash command.$q$, $q$Enterprise governance features including SOC 2 Type II, HIPAA, and GxP compliance, SSO, SCIM provisioning, and permission-aware answers ensure AI-generated responses only surface information a given employee is authorized to see.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Guru sells three tiers, Starter, Builder, and Expert (Enterprise), all priced per seat with a 10-seat minimum, and does not offer a permanent free plan, though it provides a 30-day free trial.$q$, $q$Starter pricing is publicly listed at $25 per seat per month on annual billing, putting the effective floor at $250 per month, while Builder and Expert pricing require contacting Guru's sales team for a custom quote.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('79fe800c-3b4a-461b-be9d-1206811b507d', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Full-service payroll$q$, $q$Automatically calculates, withholds, files, and remits federal, state, and local payroll taxes, with flexible pay schedules and direct deposit.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Benefits administration and brokerage$q$, $q$Offers health insurance, dental and vision coverage, 401(k) retirement plans, and HSAs, often at group rates negotiated on behalf of small employers.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Contractor payments$q$, $q$Supports paying 1099 contractors alongside W-2 employees, including a dedicated Contractor Only plan for businesses with no traditional employees.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Time tracking and PTO management$q$, $q$Plus and Premium plans include time tracking and paid-time-off management integrated directly with payroll.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Employee self-service portal$q$, $q$Employees can view pay stubs, tax documents, and benefits information, and manage their own profile, without HR needing to intervene.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Onboarding workflows$q$, $q$Automates new-hire paperwork, tax form collection, and benefits enrollment as part of the onboarding process.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Compliance support$q$, $q$Helps small businesses stay compliant with new-hire reporting, workers' compensation, and other regulatory requirements tied to payroll and employment.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$HR support resources$q$, $q$Premium plan customers get access to more advanced HR support and compliance resources for complex workforce needs.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Transparent, published pricing makes it easy to estimate costs upfront, unlike many legacy payroll providers that require a custom quote.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Automatic tax calculation, filing, and remittance significantly reduces the compliance burden on small business owners.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Integrated benefits brokerage lets small employers offer competitive health insurance and retirement plans without a separate broker relationship.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Modern, self-service interface is designed specifically for small business owners rather than enterprise HR departments.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Dedicated Contractor Only plan offers a lower-cost option for businesses that don't need full payroll tax handling.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Per-employee pricing on top of the base fee means costs scale up meaningfully as headcount grows, particularly on the Premium tier.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Advanced HR and compliance features are reserved for the higher-priced Plus and Premium tiers rather than being available on Simple.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Simple plan base pricing increased from $40 to $49 per month in March 2026, raising the entry cost for the smallest businesses.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Less suited to companies with significant international or globally distributed workforces compared to competitors like Deel.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$As the company has grown toward and past $1 billion in revenue scale, some smaller customers report that support responsiveness has become less personal than in Gusto's earlier years.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$How much does Gusto cost?$q$, $q$Gusto's 2026 pricing has three main tiers: Simple at $49 per month plus $6 per employee per month, Plus at $80 per month plus $12 per employee per month, and Premium at $180 per month plus $22 per employee per month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$When was Gusto founded?$q$, $q$Gusto was founded in 2011 by Joshua Reeves, Tomer London, and Edward Kim, launching publicly in December 2012 under the name ZenPayroll before rebranding to Gusto in 2015.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Does Gusto handle payroll taxes automatically?$q$, $q$Yes, Gusto automatically calculates, withholds, files, and remits federal, state, and local payroll taxes on the employer's behalf as part of every plan.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Can Gusto pay contractors as well as employees?$q$, $q$Yes, Gusto supports paying both W-2 employees and 1099 contractors, and offers a dedicated Contractor Only plan for businesses that have no traditional employees.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Does Gusto offer employee benefits?$q$, $q$Yes, Gusto provides benefits administration and brokerage services covering health insurance, dental and vision coverage, retirement plans, and health savings accounts.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$How big is Gusto as a company?$q$, $q$As of 2026, Gusto employs approximately 4,000 people, serves more than 500,000 businesses, has surpassed $1 billion in annual revenue, and carries a valuation of roughly $9.3 billion.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Automated small business payroll$q$, $q$Small business owners use Gusto to run payroll on a set schedule while taxes are automatically calculated, withheld, and filed on their behalf.$q$, $q$Small business owners and office managers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Employee benefits administration$q$, $q$Growing companies use Gusto to offer and administer health insurance and retirement benefits without hiring a dedicated HR or benefits specialist.$q$, $q$HR teams at small and mid-sized companies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Contractor-only payments$q$, $q$Agencies and startups that work exclusively with freelancers use Gusto's Contractor Only plan to pay 1099 workers without full payroll tax overhead.$q$, $q$Businesses with contractor-only workforces$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Simple$q$, $q$$49/month + $6/employee/month$q$, $q$Monthly$q$, NULL, $q$["Full-service payroll","Automatic tax filing","Employee self-service portal","Basic benefits administration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Plus$q$, $q$$80/month + $12/employee/month$q$, $q$Monthly$q$, NULL, $q$["Everything in Simple","Time tracking and PTO management","Advanced onboarding workflows","Additional compliance features"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Premium$q$, $q$$180/month + $22/employee/month$q$, $q$Monthly$q$, NULL, $q$["Everything in Plus","Dedicated HR support","Advanced compliance resources","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$Contractor Only$q$, $q$$35/month + $6/contractor/month$q$, $q$Monthly$q$, NULL, $q$["Contractor payments only","No W-2 payroll tax handling needed","Direct deposit for contractors"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Gusto is a cloud-based payroll, benefits, and HR platform for small and medium-sized businesses, founded in 2011 by Joshua Reeves, Tomer London, and Edward Kim and originally launched under the name ZenPayroll before rebranding to Gusto in 2015.$q$, $q$Headquartered in San Francisco, Gusto has raised roughly $718 million in funding, surpassed $1 billion in annual revenue by early 2026, and now serves more than 500,000 businesses with a valuation of about $9.3 billion.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Gusto's core product automatically calculates, withholds, files, and remits federal, state, and local payroll taxes on the employer's behalf, alongside direct deposit for both W-2 employees and 1099 contractors.$q$, $q$Beyond payroll, the platform bundles benefits administration and brokerage for health insurance, retirement plans, and other perks, plus HR tools like onboarding, time tracking, PTO management, and compliance support.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Gusto's 2026 pricing follows a base-fee-plus-per-employee model across three plans: Simple at $49 per month plus $6 per employee, Plus at $80 per month plus $12 per employee, and Premium at $180 per month plus $22 per employee.$q$, $q$A dedicated Contractor Only plan at $35 per month plus $6 per contractor per month serves businesses with no W-2 employees, skipping payroll tax withholding features that aren't needed for 1099-only relationships.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('fbffcaa4-b264-4a87-bd4b-d1c6cc1e9c14', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
