-- ── Group Office ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Group Office is an open source groupware and CRM suite offering email, calendar, file sharing, and project tools that can be self-hosted or run on the vendor's cloud.$q$, short_description),
  pricing_model = COALESCE($q$Open Source, Freemium (free self-hosted Community edition plus paid cloud and add-ons)$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); Online plan from $12/month$q$, starting_price),
  founded_year = COALESCE(2003, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$'s-Hertogenbosch, Netherlands$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Group Office Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Group Office review covering its open source groupware and CRM features, self-hosted versus cloud pricing, key features, pros, cons, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Group Office is an open source groupware, customer relationship management (CRM), and document management platform developed by the Dutch company Intermesh. It bundles the core tools a small or mid-sized organization needs to collaborate: email, shared calendars, contact and address book management, file storage and sharing, task and project tracking, time tracking, invoicing and quoting, a helpdesk and support ticketing module, and integration with the Collabora Online office suite for in-browser document editing. The product is aimed squarely at organizations, including public-sector bodies, that want a self-hosted or privately controlled alternative to hosted suites like Google Workspace or Microsoft 365, either for cost, data sovereignty, or customization reasons. Group Office traces back to an initial release distributed via SourceForge in 2003, making it one of the longer-running open source groupware projects still under active development. It is built and maintained by Intermesh, a software company headquartered in 's-Hertogenbosch, the Netherlands. The product is written in PHP and distributed under a dual-license model: the Community edition, known as Group Office Community, is released under the AGPL open source license and is available on GitHub for anyone to self-host and modify, while Intermesh also sells a commercial Professional edition and a hosted cloud version for organizations that prefer a managed deployment. Architecturally, Group Office is a traditional server-side PHP web application backed by a relational database, designed to be deployed on a standard LAMP-style stack or run through Intermesh's own cloud infrastructure. Self-hosting gives an organization full control over where its email, files, and business data live, which is a common driver for adoption among government agencies, schools, and privacy-conscious businesses in Europe. The cloud-hosted option removes the operational burden of running and patching a server while still keeping data within Intermesh's infrastructure rather than a large US hyperscaler-hosted SaaS suite. On features, the free, self-hosted Community edition includes the core groupware stack: email, calendar, address book, file storage, document editing, notes, tasks, and device sync, along with free updates and patches for an unlimited number of users. The paid Professional edition adds business-oriented modules on top of that core: support ticketing, time tracking, project management, an email newsletter tool, a Kanban board (called Studio for building custom apps), and helpdesk support from Intermesh during business hours (9 to 5 CET/CEST). Additional paid add-ons are available a la carte, including a dedicated document editor integration, chat and video calling built on Rocket.Chat, a finance and billing module for invoice management and payments, and an expanded document search and e-discovery capability. Intermesh also sells professional services contracts covering server installation with SSL setup, mailserver configuration, and document-editing server setup, each typically scoped for organizations of up to 100 users with phone support during business hours. Pricing follows the open-core groupware pattern common in this category. The Community edition is free to download, self-host, and use with unlimited users, though it excludes the paid business modules. The Professional edition is licensed for a one-time fee of around 439 euros with roughly 219 euros per year for continued updates, scoped for one to 100 users, with larger deployments requiring a custom quote from Intermesh. Group Office also offers a cloud-hosted Online plan starting at around 12 dollars per month for organizations that don't want to self-host at all. Storage and specific feature add-ons are priced separately on a per-user or flat-fee basis, and additional cloud storage can be purchased in increments. Group Office's target audience is small and mid-sized businesses, schools, nonprofits, and government or public-sector organizations that need an integrated email, calendar, file-sharing, and CRM and project suite but want to avoid vendor lock-in to a large commercial SaaS platform. It competes with other open source groupware and productivity suites such as EGroupware, Nextcloud, Zimbra, and, to a lesser extent, commercial suites like Google Workspace and Microsoft 365. Its key differentiator versus most of those competitors is the breadth of built-in business functionality, CRM, invoicing, helpdesk, and project management alongside core groupware, bundled into a single AGPL-licensed open source codebase that has been maintained continuously since 2003.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '75c612e3-c807-4326-9997-c8d5eb872687';

