-- ── GrowthBook ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$GrowthBook is an open source feature flagging, A/B testing, and product analytics platform that connects directly to a company's existing data warehouse.$q$, short_description),
  pricing_model = COALESCE($q$Open Source, Freemium (free self-hosted or Starter cloud, paid Pro and Enterprise)$q$, pricing_model),
  starting_price = COALESCE($q$Free (Pro from $40/seat/month)$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$About 40 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$GrowthBook Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$GrowthBook review covering its open source feature flagging and A/B testing platform, warehouse-native architecture, pricing tiers, pros, cons, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$GrowthBook is an open source platform that combines feature flagging, A/B testing and experimentation, and product analytics into a single tool that engineering and product teams can either self-host for free or run on GrowthBook's managed cloud. Its defining architectural choice is being warehouse-native: rather than requiring customers to pipe event data into a proprietary analytics store the way most commercial experimentation platforms do, GrowthBook connects directly to a company's existing data warehouse, such as Snowflake, BigQuery, Redshift, ClickHouse, or Postgres, and runs its statistical analysis against data that already lives there. That design avoids duplicating event data into a third-party system and lets data teams keep a single source of truth for experiment results, funnel metrics, and product analytics. GrowthBook was founded in 2020 by Jeremy Dorn and Graham McNicoll and is headquartered in San Francisco. The company went through Y Combinator's Winter 2022 batch and has grown to roughly 40 employees. It is structured as an open core business: the bulk of the GrowthBook codebase is released under the permissive MIT license and hosted publicly on GitHub, where the growthbook/growthbook repository has crossed roughly 7,700 stars, and GrowthBook says the platform is now used by more than 3,000 companies. On the funding side, GrowthBook raised a Series A round announced in June 2025, bringing its total funding to approximately $23.1 million from investors including Khosla Ventures and Y Combinator, on top of its earlier YC seed backing. Technically, GrowthBook offers two related but distinct product surfaces. The feature flagging product lets engineering teams roll features out gradually, target specific user segments, and kill-switch problematic releases without a redeploy, with SDKs available across major languages and frameworks. The experimentation product layers A/B testing, multi-armed bandits, and safe rollout mechanics on top of that flagging infrastructure, using GrowthBook's own Bayesian and frequentist statistics engine to analyze results computed directly against warehouse data rather than a separate proprietary event pipeline. The product analytics layer adds funnel, retention, and metric-tracking capabilities so product teams can evaluate feature and experiment impact using the same underlying data model. Because everything runs against the customer's own warehouse, GrowthBook can be deployed with a bring-your-own-warehouse model on every tier, including the free plan, which is unusual among warehouse-native experimentation platforms that often gate this architecture behind higher-priced tiers. GrowthBook's pricing is split between cloud-hosted and self-hosted paths, each with a free tier. On GrowthBook Cloud, the Starter plan is free for up to 3 users and includes unlimited feature flags, unlimited experiments, a choice of bring-your-own-warehouse or a GrowthBook-managed warehouse, unlimited traffic, and community support. The Pro plan is $40 per seat per month for up to 50 users and adds a visual editor for no-code experiment setup, multi-armed bandits, safe rollout controls, customizable dashboards, advanced permissioning, a statistical power calculator, and premium support. The Enterprise plan is custom-priced and adds ramp schedules, approval workflows, advanced access control, SSO and SCIM provisioning, exportable audit logs, a 99.99 percent uptime SLA, large-dataset optimizations, and dedicated support and training. For teams that want to self-host, GrowthBook's Open Source tier is free and includes unlimited feature flags and experiments with a bring-your-own-warehouse model and community support, while a self-hosted Enterprise tier is available at custom pricing with the same advanced access control, SSO/SCIM, data pipeline, visual editor, multi-armed bandit, safe rollout, sticky bucketing, and holdout features as the cloud Enterprise plan, plus dedicated support. GrowthBook's target audience spans engineering, product, and data teams at companies of nearly any size, from early-stage startups self-hosting the open source edition for free, up to larger organizations that need SSO, audit logs, and dedicated support on the Enterprise tier. Competitively, GrowthBook sits alongside commercial feature flagging and experimentation platforms such as LaunchDarkly, Optimizely, Statsig, and Split, as well as open source feature-flag-only projects like Unleash and Flagsmith. Its primary differentiators are the combination of a genuinely open source, MIT-licensed core with a free self-hosting option, the warehouse-native architecture that avoids vendor lock-in and duplicate data pipelines, and a single unified product spanning feature flags, experimentation, and product analytics rather than requiring separate point tools for each.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '97fb4c3c-be2d-434f-9e6a-cd5f7f600da0';

