-- ── GrowthLoop ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$GrowthLoop is a composable customer data platform that activates audiences, journeys, and AI-driven marketing campaigns directly from a company's cloud data warehouse.$q$, short_description),
  pricing_model = COALESCE($q$Subscription (custom quote based on customer records)$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing (contact sales)$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$San Francisco, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$GrowthLoop Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$GrowthLoop review covering its composable CDP built on the data warehouse, AI-driven audience activation, pricing tiers, key features, pros, cons, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$GrowthLoop is a composable customer data platform (CDP) that lets marketing teams build audiences, orchestrate customer journeys, and run AI-driven campaigns directly on top of a company's existing cloud data warehouse, such as Snowflake, BigQuery, Databricks, or Redshift, instead of requiring customer data to be copied into a separate, vendor-owned data store. The composable label refers to this architectural approach, which has become an increasingly common alternative to traditional, monolithic CDPs: rather than owning and hosting a copy of a company's customer data, GrowthLoop reads and writes directly against the warehouse the company already operates, reducing data duplication, latency, and governance risk while letting marketing teams build audience segments and activate them across advertising, email, SMS, and other channels. The company's roots go back to 2015, when it was founded as Flywheel Software by David Joosten and Chris Sell, who met while working as marketers at Google and experienced firsthand how difficult it was to access and activate customer data for marketing purposes inside large organizations. Flywheel Software later rebranded as GrowthLoop as the product evolved from its original form into the composable CDP category. The company is based in San Francisco, with additional presence reported in New York and Toronto. In April 2026, GrowthLoop appointed co-CEOs Anthony Rotio and Tameem Iftikhar, reflecting a leadership transition as the company scales. On the funding side, GrowthLoop has raised a total of roughly $93.8 million, including a growth equity investment from The Jordan Company announced in May 2022, and a Series D round in October 2025. Product-wise, GrowthLoop's core capability is self-serve audience building: marketers can construct unlimited active and saved audience segments and unlimited audience templates directly against warehouse tables, without needing a data engineer to write custom SQL for every new segment. Those audiences can then be pushed to an unlimited set of downstream destinations, such as ad platforms, email and SMS providers, and other marketing tools, for activation. Beyond simple audience export, GrowthLoop layers in journey personalization and experimentation tooling for orchestrating multi-step, omnichannel customer journeys, and an AI Studio that includes growth agents and agentic recommendations designed to automate parts of the campaign-building and optimization process. The platform also includes incrementality and uplift measurement tools to help marketing teams quantify the actual causal impact of campaigns rather than relying on last-touch attribution, along with audience, journey, and channel-level insights and reporting. On governance and security, GrowthLoop supports unlimited users with role- and feature-based access control, SOC 2 Type II compliance, PII management tooling, a query-in-place model that avoids unnecessarily copying sensitive data out of the warehouse, data governance controls, an application firewall, and SSO support. GrowthLoop's pricing is entirely custom and quote-based; the company does not publish self-serve list pricing. Its plans are tiered primarily by the number of customer records under management: a Basic tier for up to 1 million customer records, a Growth tier for up to 10 million records, and an Enterprise tier for 10 million-plus records, with each tier requiring a sales conversation to get an actual quote. Core platform capabilities are available across all tiers, with Basic and Growth including standard email and Slack-based support and standard onboarding, while Enterprise adds a dedicated solutions architect, data engineering support, and hands-on launch services. GrowthLoop's target audience is mid-market to enterprise marketing and growth teams, particularly at consumer brands, retailers, financial services companies, and other organizations with substantial first-party customer data already centralized in a modern cloud data warehouse. Competitively, GrowthLoop sits in the composable CDP category alongside vendors like Hightouch and Census, as well as more traditional, all-in-one customer data platforms such as Segment, Braze, and Adobe's customer data offerings. Its key differentiator versus traditional CDPs is the warehouse-native, query-in-place architecture combined with an increasing emphasis on agentic AI tooling for automating audience building, journey orchestration, and campaign optimization, positioning GrowthLoop as an agentic composable CDP for marketing teams that want AI-assisted activation without giving up governance over where their customer data actually lives.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '45050474-ebf1-4a46-89d7-f47f4521c45f';

